import{_ as e,o as r,c as a,ag as o}from"./chunks/framework.6MCaaFDc.js";const m=JSON.parse('{"title":"Types of Computers","description":"","frontmatter":{},"headers":[],"relativePath":"theory/systems/types-of-computers.md","filePath":"theory/systems/types-of-computers.md"}'),d={name:"theory/systems/types-of-computers.md"};function s(n,t,i,l,c,p){return r(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="types-of-computers" tabindex="-1">Types of Computers <a class="header-anchor" href="#types-of-computers" aria-label="Permalink to &quot;Types of Computers&quot;">​</a></h1><p>Not all computers look like the desktop in a lab. A microwave, a smartwatch, and a supercomputer are all computers — they all receive input, process it, and produce output. What differs is their size, power, purpose, and portability.</p><div class="note custom-block github-alert"><p class="custom-block-title">Grade 10+</p><p>Types of computers and their characteristics are introduced in Grade 10. Mobile technology and embedded systems extend into Grade 12.</p></div><hr><h2 id="classification-by-size-and-power" tabindex="-1">Classification by Size and Power <a class="header-anchor" href="#classification-by-size-and-power" aria-label="Permalink to &quot;Classification by Size and Power&quot;">​</a></h2><h3 id="microcomputers-personal-computers" tabindex="-1">Microcomputers (Personal Computers) <a class="header-anchor" href="#microcomputers-personal-computers" aria-label="Permalink to &quot;Microcomputers (Personal Computers)&quot;">​</a></h3><p>The most common type — used by individuals. All the devices below are microcomputers.</p><hr><h3 id="desktop-computer" tabindex="-1">Desktop Computer <a class="header-anchor" href="#desktop-computer" aria-label="Permalink to &quot;Desktop Computer&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Aspect</th><th>Detail</th></tr></thead><tbody><tr><td><strong>Location</strong></td><td>Fixed on a desk — not portable</td></tr><tr><td><strong>Components</strong></td><td>Separate: tower/case, monitor, keyboard, mouse</td></tr><tr><td><strong>Power</strong></td><td>Plugged into mains power</td></tr><tr><td><strong>Performance</strong></td><td>High — larger components, better cooling, upgradeable</td></tr><tr><td><strong>Use</strong></td><td>Offices, labs, gaming, graphic design</td></tr><tr><td><strong>Advantages</strong></td><td>Upgradeable, better cooling, larger screen, cheaper per spec</td></tr><tr><td><strong>Disadvantages</strong></td><td>Not portable, requires desk space</td></tr></tbody></table><hr><h3 id="laptop-notebook" tabindex="-1">Laptop (Notebook) <a class="header-anchor" href="#laptop-notebook" aria-label="Permalink to &quot;Laptop (Notebook)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Aspect</th><th>Detail</th></tr></thead><tbody><tr><td><strong>Components</strong></td><td>Integrated: screen, keyboard, touchpad in one unit</td></tr><tr><td><strong>Power</strong></td><td>Battery + power adapter</td></tr><tr><td><strong>Performance</strong></td><td>Good — slightly lower than desktop for same price</td></tr><tr><td><strong>Use</strong></td><td>Students, professionals, home users who need mobility</td></tr><tr><td><strong>Advantages</strong></td><td>Portable, built-in battery, all-in-one</td></tr><tr><td><strong>Disadvantages</strong></td><td>Less upgradeable, smaller screen, can overheat, battery life limited</td></tr></tbody></table><hr><h3 id="tablet" tabindex="-1">Tablet <a class="header-anchor" href="#tablet" aria-label="Permalink to &quot;Tablet&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Aspect</th><th>Detail</th></tr></thead><tbody><tr><td><strong>Interface</strong></td><td>Touchscreen — no physical keyboard (can attach external)</td></tr><tr><td><strong>OS</strong></td><td>Android, iPadOS, Windows</td></tr><tr><td><strong>Power</strong></td><td>Battery</td></tr><tr><td><strong>Use</strong></td><td>Reading, media consumption, light productivity, education</td></tr><tr><td><strong>Advantages</strong></td><td>Very portable, lightweight, long battery life, intuitive touch</td></tr><tr><td><strong>Disadvantages</strong></td><td>Less powerful than laptop, limited software, typing is slower</td></tr></tbody></table><hr><h3 id="smartphone" tabindex="-1">Smartphone <a class="header-anchor" href="#smartphone" aria-label="Permalink to &quot;Smartphone&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Aspect</th><th>Detail</th></tr></thead><tbody><tr><td><strong>Interface</strong></td><td>Touchscreen, voice</td></tr><tr><td><strong>OS</strong></td><td>Android, iOS</td></tr><tr><td><strong>Connectivity</strong></td><td>4G/5G, WiFi, Bluetooth, GPS</td></tr><tr><td><strong>Use</strong></td><td>Communication, social media, navigation, mobile banking, photography</td></tr><tr><td><strong>Advantages</strong></td><td>Always connected, GPS, camera, extremely portable</td></tr><tr><td><strong>Disadvantages</strong></td><td>Small screen, limited processing power vs laptop, security risks</td></tr></tbody></table><hr><h3 id="smartwatch-wearable" tabindex="-1">Smartwatch / Wearable <a class="header-anchor" href="#smartwatch-wearable" aria-label="Permalink to &quot;Smartwatch / Wearable&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Aspect</th><th>Detail</th></tr></thead><tbody><tr><td><strong>Interface</strong></td><td>Small touchscreen, voice</td></tr><tr><td><strong>Use</strong></td><td>Health monitoring (HR, steps), notifications, contactless payment</td></tr><tr><td><strong>Limitations</strong></td><td>Small screen, limited input, depends on paired phone</td></tr><tr><td><strong>Examples</strong></td><td>Apple Watch, Samsung Galaxy Watch, Fitbit</td></tr></tbody></table><hr><h2 id="server" tabindex="-1">Server <a class="header-anchor" href="#server" aria-label="Permalink to &quot;Server&quot;">​</a></h2><p>A <strong>server</strong> is a powerful computer that provides services to other computers (clients) on a network.</p><table tabindex="0"><thead><tr><th>Type</th><th>Purpose</th></tr></thead><tbody><tr><td><strong>File server</strong></td><td>Stores and shares files across a network</td></tr><tr><td><strong>Web server</strong></td><td>Hosts websites, serves web pages to browsers</td></tr><tr><td><strong>Mail server</strong></td><td>Manages email (sending, receiving, storing)</td></tr><tr><td><strong>Database server</strong></td><td>Runs a database and responds to queries</td></tr><tr><td><strong>Print server</strong></td><td>Manages shared printers on a network</td></tr><tr><td><strong>Application server</strong></td><td>Runs applications and delivers them to clients</td></tr></tbody></table><p><strong>Server characteristics:</strong></p><ul><li>Runs 24/7 (uptime is critical)</li><li>No monitor or keyboard usually attached (managed remotely via CLI)</li><li>Multiple CPU cores and large RAM</li><li>Redundant storage (RAID) to prevent data loss</li><li>Runs a <strong>Network Operating System (NOS)</strong> like Windows Server or Linux</li></ul><hr><h2 id="mainframe" tabindex="-1">Mainframe <a class="header-anchor" href="#mainframe" aria-label="Permalink to &quot;Mainframe&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Aspect</th><th>Detail</th></tr></thead><tbody><tr><td><strong>Size</strong></td><td>Large room-filling systems</td></tr><tr><td><strong>Users</strong></td><td>Hundreds to thousands simultaneously</td></tr><tr><td><strong>Use</strong></td><td>Banking transactions, airline reservations, government databases</td></tr><tr><td><strong>Performance</strong></td><td>Exceptionally reliable, processes millions of transactions per second</td></tr><tr><td><strong>Examples</strong></td><td>IBM Z Series</td></tr></tbody></table><hr><h2 id="supercomputer" tabindex="-1">Supercomputer <a class="header-anchor" href="#supercomputer" aria-label="Permalink to &quot;Supercomputer&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Aspect</th><th>Detail</th></tr></thead><tbody><tr><td><strong>Speed</strong></td><td>Fastest computers in existence — measured in FLOPS (floating point operations per second)</td></tr><tr><td><strong>Use</strong></td><td>Weather forecasting, nuclear simulation, climate modelling, drug research</td></tr><tr><td><strong>Cost</strong></td><td>Millions to billions of rands</td></tr><tr><td><strong>Power</strong></td><td>Consumes enormous electricity; requires dedicated cooling</td></tr><tr><td><strong>Examples</strong></td><td>Frontier (USA), Fugaku (Japan)</td></tr></tbody></table><hr><h2 id="embedded-systems" tabindex="-1">Embedded Systems <a class="header-anchor" href="#embedded-systems" aria-label="Permalink to &quot;Embedded Systems&quot;">​</a></h2><p>An <strong>embedded system</strong> is a computer built into a device for a specific, dedicated purpose. The user doesn&#39;t see it as a &quot;computer.&quot;</p><table tabindex="0"><thead><tr><th>Device</th><th>Embedded Computer Function</th></tr></thead><tbody><tr><td>Smart TV</td><td>Process remote commands, stream video, display output</td></tr><tr><td>Microwave oven</td><td>Timer management, power level control</td></tr><tr><td>Modern car</td><td>Engine management, ABS, GPS navigation, entertainment</td></tr><tr><td>ATM machine</td><td>Process banking transactions, control card reader</td></tr><tr><td>Medical pacemaker</td><td>Monitor heart rate, deliver shocks when needed</td></tr><tr><td>Traffic light</td><td>Control timing sequence, respond to sensors</td></tr><tr><td>Industrial robot</td><td>Precise movement control, sensor response</td></tr></tbody></table><p><strong>Characteristics:</strong></p><ul><li>Dedicated single purpose — can&#39;t be reprogrammed by user</li><li>Real-time OS (must respond instantly)</li><li>Small, energy-efficient, often no display</li><li>Highly reliable (failure can be dangerous)</li></ul><hr><h2 id="comparison-table" tabindex="-1">Comparison Table <a class="header-anchor" href="#comparison-table" aria-label="Permalink to &quot;Comparison Table&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Type</th><th>Portable?</th><th>Multi-user?</th><th>Dedicated purpose?</th><th>Typical Use</th></tr></thead><tbody><tr><td>Desktop</td><td>✗</td><td>✗</td><td>✗</td><td>Personal productivity</td></tr><tr><td>Laptop</td><td>✓</td><td>✗</td><td>✗</td><td>Mobile personal use</td></tr><tr><td>Tablet</td><td>✓</td><td>✗</td><td>✗</td><td>Media, education</td></tr><tr><td>Smartphone</td><td>✓</td><td>✗</td><td>✗</td><td>Communication, apps</td></tr><tr><td>Server</td><td>✗</td><td>✓</td><td>✗</td><td>Network services</td></tr><tr><td>Mainframe</td><td>✗</td><td>✓</td><td>✗</td><td>Mass transactions</td></tr><tr><td>Supercomputer</td><td>✗</td><td>✓</td><td>✗</td><td>Scientific computation</td></tr><tr><td>Embedded system</td><td>Varies</td><td>✗</td><td>✓</td><td>One specific task</td></tr></tbody></table><hr><h2 id="mobile-technology" tabindex="-1">Mobile Technology <a class="header-anchor" href="#mobile-technology" aria-label="Permalink to &quot;Mobile Technology&quot;">​</a></h2><div class="important custom-block github-alert"><p class="custom-block-title">Grade 12 — Mastery</p><p>Mobile technology and its advantages/limitations are a Grade 12 focus topic.</p></div><h3 id="advantages-of-mobile-devices" tabindex="-1">Advantages of Mobile Devices <a class="header-anchor" href="#advantages-of-mobile-devices" aria-label="Permalink to &quot;Advantages of Mobile Devices&quot;">​</a></h3><ul><li>Portability — take your work/data anywhere</li><li>Always connected via 4G/5G/WiFi</li><li>GPS and location services</li><li>Integrated camera, microphone, sensors</li><li>Long battery life vs laptop</li><li>Cloud sync keeps data updated across devices</li></ul><h3 id="limitations-of-mobile-devices" tabindex="-1">Limitations of Mobile Devices <a class="header-anchor" href="#limitations-of-mobile-devices" aria-label="Permalink to &quot;Limitations of Mobile Devices&quot;">​</a></h3><ul><li><strong>Processing power</strong> — less than desktop/laptop</li><li><strong>Storage</strong> — limited internal storage (mitigated by cloud)</li><li><strong>Screen size</strong> — small display limits usability</li><li><strong>Input method</strong> — touchscreen typing slower than physical keyboard</li><li><strong>Battery life</strong> — still limited, needs regular charging</li><li><strong>Security</strong> — more vulnerable to loss/theft; app-based malware risks</li><li><strong>Connectivity dependence</strong> — many features require internet access</li></ul><h3 id="_4g-vs-5g" tabindex="-1">4G vs 5G <a class="header-anchor" href="#_4g-vs-5g" aria-label="Permalink to &quot;4G vs 5G&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Feature</th><th>4G LTE</th><th>5G</th></tr></thead><tbody><tr><td>Max download speed</td><td>~150 Mbps</td><td>~10 Gbps</td></tr><tr><td>Latency</td><td>~30–50 ms</td><td>&lt;1 ms</td></tr><tr><td>Connected devices per area</td><td>Lower capacity</td><td>Much higher density</td></tr><tr><td>Use cases</td><td>Video streaming, general mobile</td><td>Autonomous vehicles, IoT, AR/VR</td></tr></tbody></table><hr><h2 id="key-terms" tabindex="-1">Key Terms <a class="header-anchor" href="#key-terms" aria-label="Permalink to &quot;Key Terms&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Term</th><th>Definition</th></tr></thead><tbody><tr><td><strong>Desktop computer</strong></td><td>Non-portable personal computer with separate components</td></tr><tr><td><strong>Laptop</strong></td><td>Portable all-in-one personal computer with built-in battery</td></tr><tr><td><strong>Tablet</strong></td><td>Touchscreen portable device, usually no physical keyboard</td></tr><tr><td><strong>Server</strong></td><td>Computer that provides services to networked client computers</td></tr><tr><td><strong>Mainframe</strong></td><td>Large, multi-user computer handling massive transaction volumes</td></tr><tr><td><strong>Supercomputer</strong></td><td>Fastest computers used for scientific simulations</td></tr><tr><td><strong>Embedded system</strong></td><td>Computer built into a device for a single dedicated purpose</td></tr><tr><td><strong>RTOS</strong></td><td>Real-Time Operating System — responds to inputs with no delay</td></tr><tr><td><strong>FLOPS</strong></td><td>Floating Point Operations Per Second — measure of supercomputer speed</td></tr><tr><td><strong>4G/5G</strong></td><td>Mobile network standards; 5G is faster with lower latency</td></tr><tr><td><strong>Wearable</strong></td><td>Computer worn on the body (watch, fitness tracker)</td></tr></tbody></table><hr><h2 id="exam-focus" tabindex="-1">Exam Focus <a class="header-anchor" href="#exam-focus" aria-label="Permalink to &quot;Exam Focus&quot;">​</a></h2><div class="important custom-block github-alert"><p class="custom-block-title">High-Frequency Questions</p><p></p><ol><li><p><strong>&quot;Name the type of computer and give a reason for your answer&quot;</strong> — identify desktop/laptop/tablet/server/embedded from a scenario</p></li><li><p><strong>&quot;Give TWO advantages of a laptop over a desktop&quot;</strong> — portability, battery, all-in-one; avoid vague answers like &quot;better&quot;</p></li><li><p><strong>&quot;What is an embedded system? Give an example.&quot;</strong> — built into a device for a dedicated single purpose; example must be specific (not just &quot;a computer in a car&quot; but &quot;the engine management system in a car&quot;)</p></li><li><p><strong>&quot;Compare 4G and 5G in terms of speed and latency&quot;</strong> — know the numbers and what lower latency enables</p></li></ol></div>',58)])])}const g=e(d,[["render",s]]);export{m as __pageData,g as default};
